&lt;p&gt;&amp;rArr;&amp;nbsp;&lt;span class=&quot;math-tex&quot; style=&quot;outline: yellow solid 2px; cursor: default; ;&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \times \left\{ \frac{24}{5} \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

