&lt;p&gt;&lt;span class=&quot;math-tex&quot;&gt;\(7 \frac{1}{4} - \left[ \frac{5}{6} \div \left\{ \frac{1}{3} - \left( \frac{1}{2} \times \left( \frac{3}{4} - \frac{1}{2} \right) \right) \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गणना:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; &lt;span class=&quot;math-tex&quot;&gt;\(7 \frac{1}{4} - \left[ \frac{5}{6} \div \left\{ \frac{1}{3} - \left( \frac{1}{2} \times \left( \frac{3}{4} - \frac{1}{2} \right) \right) \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; &lt;span class=&quot;math-tex&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \div \left\{ \frac{1}{3} - \left( \frac{1}{2} \times \left( \frac{3}{4} - \frac{2}{4} \right) \right) \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; &lt;/span&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \div \left\{ \frac{1}{3} - \left( \frac{1}{2} \times \left( \frac{1}{4} \right) \right) \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; &lt;/span&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \div \left\{ \frac{1}{3} - \left( \frac{1}{8} \right) \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; &lt;span class=&quot;math-tex&quot; style=&quot;outline: yellow solid 2px; cursor: default; ;&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \div \left\{ \frac{8-3}{24} \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; &lt;span class=&quot;math-tex&quot; style=&quot;outline: yellow solid 2px; cursor: default; ;&quot;&gt;\(\frac{29}{4} - \left[ \frac{5}{6} \times \left\{ \frac{24}{5} \right\} \right]\)&lt;/span&gt;&lt;/p&gt;

